          // Nowy, bezpieczny spos\xf3b dla Androida 13 i nowszych\n            intent.getSerializableExtra("CAR_DATA", FutureCar::class.java)\n        } else {\n            // Stary spos\xf3b dla starszych telefon\xf3w\n            @Suppress("DEPRECATION") // M\xf3wimy kompilatorowi: "Wiem, co robi\u0119, przesta\u0144 narzeka\u0107"\n            intent.getSerializableExtra("CAR_DATA") as? FutureCar\n        }\n\n        //  Sprawdzamy, czy paczka dotar\u0142a bezpiecznie\n        if (car != null) {\n            // Wstrzykujemy dane do interfejsu\n            binding.detailNameTextView.text = car.name\n            binding.detailYearTextView.text = "Rok produkcji: ${car.productionYear}"\n            binding.detailSpeedTextView.text = "Pr\u0119dko\u015b\u0107 max: ${car.topSpeed} km/h"\n            // Formatuje cen\u0119 - taki ma\u0142y detal dla lepszego wygl\u0105du\n            binding.detailPriceTextView.text = "Cena: ${car.price} PLN"\n            binding.detailDeliveryTextView.text = "Czas dostawy: ${car.deliveryTime}"\n\n            // Zlecamy Malarzowi (Glide) pobranie wielkiego zdj\u0119cia w pe\u0142nej krasie\n            Glide.with(this)\n                .load(car.imageUrl)\n                .placeholder(R.mipmap.ic_launcher) // Za\u015blepka w trakcie \u0142adowania z chmury\n                .into(binding.detailImageView)\n\n            // O\u017cywiamy nasz nowy przycisk powrotu!\n            binding.backButton.setOnClickListener {\n                finish() // To magiczne polecenie zamyka ekran detali i ods\u0142ania MainActivity\n            }\n\n        } else {\n            // Zabezpieczenie: Gdyby paczka zgin\u0119\u0142a po drodze (np. b\u0142\u0105d systemu)\n            Toast.makeText(\n                this,\n                "B\u0142\u0105d \u0142adowania danych pojazdu!",\n                Toast.LENGTH_LONG).show()\n            finish() // Zamykamy to okno i wracamy do listy\n        }\n    }\n}\n'})}),"\n",(0,t.jsxs)(n.h2,{id:"czyszczenie-search